const express = require('express');
const app = express();
const bodyParser = require('body-parser');
const cors = require('cors');

app.use(bodyParser.json());
app.use(cors());

// Endpoint for completing levels
app.post('/levels', (req, res) => {
  const levelData = req.body;
  // Check if the client-reported score and time are valid
  if (!isValidScore(levelData.score) || !isValidTime(levelData.time)) {
    return res.status(400).json({ message: 'Invalid level data' });
  }

  // Award rewards based on client-reported metrics
  const rewards = getRewards(levelData);
  res.json(rewards);
});

// Endpoint for claiming rewards
app.post('/rewards', (req, res) => {
  const rewardId = req.body.rewardId;
  // Check if the reward is valid and belongs to the user
  if (!isValidReward(rewardId)) {
    return res.status(400).json({ message: 'Invalid reward' });
  }

  // Award the reward to the user
  const user = getUser();
  user.rewards.push(rewardId);
  res.json(user);
});

// Helper functions
function isValidScore(score) {
  return score >= 0 && score <= 100;
}

function isValidTime(time) {
  return time >= 0 && time <= 60;
}

function getRewards(levelData) {
  const rewards = [];
  // Calculate the number of rewards based on the level data
  const numRewards = calculateNumRewards(levelData);
  for (let i = 0; i < numRewards; i++) {
    rewards.push({ id: generateRewardId(), type: 'coin' });
  }
  return rewards;
}

function calculateNumRewards(levelData) {
  // Calculate the number of rewards based on the level data
  const score = levelData.score;
  const time = levelData.time;
  return Math.floor(score / 10) + Math.floor(time / 60);
}

function generateRewardId() {
  // Generate a unique reward ID
  return Math.random().toString(36).substr(2, 9);
}

function isValidReward(rewardId) {
  // Check if the reward is valid and belongs to the user
  const user = getUser();
  return user.rewards.includes(rewardId);
}

function getUser() {
  // Get the current user from the session
  return { rewards: [] };
}